import{_ as i,o as t,c as r,a2 as e,j as a}from"./chunks/framework.DRBHoC6Q.js";const _=JSON.parse('{"title":"CEO 现金流驾驶舱 V3 MVP 后端主要实现说明","description":"","frontmatter":{},"headers":[],"relativePath":"V3_MVP后端主要实现说明.md","filePath":"V3_MVP后端主要实现说明.md","lastUpdated":1783323851000}'),o={name:"V3_MVP后端主要实现说明.md"};function n(d,l,h,p,u,s){return t(),r("div",null,[...l[0]||(l[0]=[e('<h1 id="ceo-现金流驾驶舱-v3-mvp-后端主要实现说明" tabindex="-1">CEO 现金流驾驶舱 V3 MVP 后端主要实现说明 <a class="header-anchor" href="#ceo-现金流驾驶舱-v3-mvp-后端主要实现说明" aria-label="Permalink to &quot;CEO 现金流驾驶舱 V3 MVP 后端主要实现说明&quot;">​</a></h1><p>文档版本：V0.1<br> 目标读者：后端、前端、产品和后续接手该项目的工程同学<br> 阅读目标：读完后能判断当前 MVP 后端已经实现了哪些确定性能力、每个模块的数据来源和计算逻辑是什么，以及前端应优先对接哪些接口。</p><h2 id="_1-当前后端实现总览" tabindex="-1">1. 当前后端实现总览 <a class="header-anchor" href="#_1-当前后端实现总览" aria-label="Permalink to &quot;1. 当前后端实现总览&quot;">​</a></h2><p>MVP 后端已经形成一条完整的确定性链路：</p><p>财务 Excel → 导入批次与原始行留存 → 四类标准业务数据 → 现金流 / 回款风险 / 付款建议规则计算 → 老板拍板事件沉淀 → AI 按需解释事件依据。</p><p>当前实现的核心原则是：规则引擎负责算结果，AI 只负责解释已有事实。也就是说，现金流缺口、回款风险等级、付款是否建议暂缓、是否进入老板拍板，都由后端确定性规则计算；AI 不重新算账、不编造数据、不替代老板决策。</p><p>当前主要数据源来自一个已发布导入批次。驾驶舱接口默认读取最新发布批次，未指定批次时不会混用未发布数据。</p><h2 id="_2-数据导入与批次发布模块" tabindex="-1">2. 数据导入与批次发布模块 <a class="header-anchor" href="#_2-数据导入与批次发布模块" aria-label="Permalink to &quot;2. 数据导入与批次发布模块&quot;">​</a></h2><h3 id="_2-1-模块职责" tabindex="-1">2.1 模块职责 <a class="header-anchor" href="#_2-1-模块职责" aria-label="Permalink to &quot;2.1 模块职责&quot;">​</a></h3><p>数据导入模块负责接收财务上传的标准 Excel，完成解析、字段标准化、基础校验、原始行留存，并在发布批次时切换驾驶舱当前数据版本。</p><p>当前只支持模板版本 V0.1 和 .xlsx 文件。上传文件会计算 SHA-256，重复文件会被拒绝，避免同一份源文件重复入库。</p><h3 id="_2-2-导入后的数据落点" tabindex="-1">2.2 导入后的数据落点 <a class="header-anchor" href="#_2-2-导入后的数据落点" aria-label="Permalink to &quot;2.2 导入后的数据落点&quot;">​</a></h3><p>一次导入会生成一个导入批次，并保留两类数据：</p><ol><li>批次级数据：文件名、模板版本、数据期间、状态、有效行数、错误行数、警告行数、发布信息和版本号。</li><li>原始行数据：每个 Sheet 的原始值、标准化值、校验状态和校验消息。</li></ol><p>原始行留存的意义是后续可以让财务或 CFO 回看“系统为什么这么算”，也方便定位 Excel 源数据问题。</p><h3 id="_2-3-发布逻辑" tabindex="-1">2.3 发布逻辑 <a class="header-anchor" href="#_2-3-发布逻辑" aria-label="Permalink to &quot;2.3 发布逻辑&quot;">​</a></h3><p>批次上传后默认进入待审核或校验失败状态。发布时会校验：</p><ul><li>批次存在；</li><li>请求版本号与当前批次版本一致；</li><li>批次没有阻断错误；</li><li>批次状态允许发布。</li></ul><p>发布成功后，当前批次变为最新已发布批次，原已发布批次会回到待审核状态。发布动作还会触发任务和老板拍板事件刷新。</p><h2 id="_3-标准业务数据模块" tabindex="-1">3. 标准业务数据模块 <a class="header-anchor" href="#_3-标准业务数据模块" aria-label="Permalink to &quot;3. 标准业务数据模块&quot;">​</a></h2><h3 id="_3-1-四类核心业务数据" tabindex="-1">3.1 四类核心业务数据 <a class="header-anchor" href="#_3-1-四类核心业务数据" aria-label="Permalink to &quot;3.1 四类核心业务数据&quot;">​</a></h3><p>当前 MVP 的计算主要建立在四类标准业务数据上：</p><table tabindex="0"><thead><tr><th>数据</th><th>作用</th><th>关键字段</th></tr></thead><tbody><tr><td>账户余额</td><td>作为现金流预测的期初余额来源</td><td>账户编码、快照日期、可用余额、受限金额、币种</td></tr><tr><td>应收款</td><td>作为预期收入、回款风险和老板拍板回款事件来源</td><td>应收编号、客户、应收金额、约定到账日、预计到账日、负责人、业务状态</td></tr><tr><td>实际回款</td><td>用于抵扣应收款未回金额</td><td>回款编号、关联应收、回款日期、回款金额、银行流水号</td></tr><tr><td>计划支出</td><td>作为现金流预测出流和付款建议来源</td><td>支出编号、支出名称、计划日期、计划金额、刚性程度、审批状态、负责人</td></tr></tbody></table><p>客户信息作为应收款的基础维度单独保存；跟进记录和任务记录属于处理过程数据，不是四张基础表的一部分。</p><h3 id="_3-2-标准数据预览" tabindex="-1">3.2 标准数据预览 <a class="header-anchor" href="#_3-2-标准数据预览" aria-label="Permalink to &quot;3.2 标准数据预览&quot;">​</a></h3><p>后端已经提供账户余额、客户、应收款、实际回款、计划支出的分页预览接口。它们主要服务于后台审核、前端下钻和联调排查。</p><p>MVP 不提供标准数据的通用增删改。发现财务源数据错误时，优先修正 Excel 并重新导入，避免系统数据和财务源文件不一致。</p><h2 id="_4-30-60-90-天现金流预测模块" tabindex="-1">4. 30 / 60 / 90 天现金流预测模块 <a class="header-anchor" href="#_4-30-60-90-天现金流预测模块" aria-label="Permalink to &quot;4. 30 / 60 / 90 天现金流预测模块&quot;">​</a></h2><h3 id="_4-1-模块职责" tabindex="-1">4.1 模块职责 <a class="header-anchor" href="#_4-1-模块职责" aria-label="Permalink to &quot;4.1 模块职责&quot;">​</a></h3><p>该模块生成未来 90 天逐日现金流曲线，并从同一条曲线中提取 30 天、60 天、90 天三个观察窗口的最低余额、最大缺口和缺口日期。</p><p>它是驾驶舱“30 / 60 / 90 天现金流”面板的后端来源，也是付款建议模块试算付款影响的共同公式来源。</p><h3 id="_4-2-数据来源" tabindex="-1">4.2 数据来源 <a class="header-anchor" href="#_4-2-数据来源" aria-label="Permalink to &quot;4.2 数据来源&quot;">​</a></h3><p>现金流预测使用以下数据：</p><ul><li>期初余额：截至基准日，每个账户最新一条有效余额快照的可用余额之和；</li><li>预计流入：未关闭应收款的未回金额，日期取预计到账日；如果没有预计到账日，则取约定到账日；</li><li>预计流出：计划支出中状态为 planned、pending、approved 的有效支出；</li><li>预测范围：从基准日开始，连续生成 90 天。</li></ul><p>如果某个账户在基准日前没有余额快照，会在结果中返回 warning。当前没有实际付款表，所以计划支出如果没有及时更新状态，可能造成重复预测，这一点也会返回 warning。</p><h3 id="_4-3-计算逻辑" tabindex="-1">4.3 计算逻辑 <a class="header-anchor" href="#_4-3-计算逻辑" aria-label="Permalink to &quot;4.3 计算逻辑&quot;">​</a></h3><p>每天预测余额的核心公式是：</p><p>当日预测余额 = 昨日预测余额 + 当日预计流入 - 当日计划流出。</p><p>第一天的“昨日预测余额”就是期初余额。</p><p>每一天都会计算：</p><ul><li>expectedInflow：当日预计到账金额；</li><li>plannedOutflow：当日计划支出金额；</li><li>netFlow：当日净流量；</li><li>predictedBalance：当日预测余额。</li></ul><p>然后分别在前 30 天、前 60 天、前 90 天窗口内计算：</p><ul><li>minimumBalance：窗口内最低预测余额；</li><li>maximumGap：安全线与最低余额之间的差额；当前安全线暂定为 0；</li><li>gapDate：最低余额出现日期；</li><li>firstBreachDate：首次低于安全线的日期；</li><li>recoveryDate：跌破安全线后，后续持续恢复到安全线以上的日期。</li></ul><h3 id="_4-4-逾期未确认收入处理" tabindex="-1">4.4 逾期未确认收入处理 <a class="header-anchor" href="#_4-4-逾期未确认收入处理" aria-label="Permalink to &quot;4.4 逾期未确认收入处理&quot;">​</a></h3><p>如果一笔应收的有效预计日期早于基准日，并且仍有未回金额，它不会被强行塞进未来现金流曲线，而是计入 overdueUnconfirmedAmount。这样可以避免“已经逾期但没到账”的款项继续美化未来余额。</p><h3 id="_4-5-当前边界" tabindex="-1">4.5 当前边界 <a class="header-anchor" href="#_4-5-当前边界" aria-label="Permalink to &quot;4.5 当前边界&quot;">​</a></h3><p>当前预测不是机器学习预测，也不是 AI 预测；它是基于现有财务事实和计划数据的滚动测算。企业真实现金流规划通常会做 30 / 60 / 90 天视角，但应明确它是经营滚动预测，不是统计学意义上的未来预测。</p><h2 id="_5-回款风险-top-3-模块" tabindex="-1">5. 回款风险 Top 3 模块 <a class="header-anchor" href="#_5-回款风险-top-3-模块" aria-label="Permalink to &quot;5. 回款风险 Top 3 模块&quot;">​</a></h2><h3 id="_5-1-模块职责" tabindex="-1">5.1 模块职责 <a class="header-anchor" href="#_5-1-模块职责" aria-label="Permalink to &quot;5.1 模块职责&quot;">​</a></h3><p>回款风险模块负责从应收款和实际回款中计算每笔应收的未回金额、逾期状态、临期状态和风险等级，并返回当前最值得关注的前三笔风险。</p><h3 id="_5-2-未回金额计算" tabindex="-1">5.2 未回金额计算 <a class="header-anchor" href="#_5-2-未回金额计算" aria-label="Permalink to &quot;5.2 未回金额计算&quot;">​</a></h3><p>每笔应收的未回金额计算方式：</p><p>未回金额 = 应收金额 - 已关联实际回款合计。</p><p>如果未回金额小于或等于 0，则该应收不再构成风险。</p><h3 id="_5-3-风险等级规则" tabindex="-1">5.3 风险等级规则 <a class="header-anchor" href="#_5-3-风险等级规则" aria-label="Permalink to &quot;5.3 风险等级规则&quot;">​</a></h3><p>当前规则版本下：</p><ul><li>红色风险：逾期 30 天及以上；或者已经逾期且未回金额大于等于 100 万；</li><li>黄色风险：已逾期但未达到红色条件；或者距离约定到账日 0 到 2 天；</li><li>绿色：未逾期且不在临期范围内。</li></ul><p>这里已经把“临期”纳入候选，只是临期默认定义为到期当天到未来 2 天。</p><h3 id="_5-4-排序规则" tabindex="-1">5.4 排序规则 <a class="header-anchor" href="#_5-4-排序规则" aria-label="Permalink to &quot;5.4 排序规则&quot;">​</a></h3><p>Top 3 候选只取红色和黄色风险。排序优先级为：</p><ol><li>红色优先于黄色；</li><li>越接近到期或已经逾期越靠前；</li><li>逾期天数越高越靠前；</li><li>未回金额越大越靠前；</li><li>应收编号作为稳定排序兜底。</li></ol><p>接口会同时返回候选总数、红色数量、黄色数量和前三笔明细，方便首页展示“Top 3”之外的数量提示。</p><h2 id="_6-付款建议-top-3-模块" tabindex="-1">6. 付款建议 Top 3 模块 <a class="header-anchor" href="#_6-付款建议-top-3-模块" aria-label="Permalink to &quot;6. 付款建议 Top 3 模块&quot;">​</a></h2><h3 id="_6-1-模块职责" tabindex="-1">6.1 模块职责 <a class="header-anchor" href="#_6-1-模块职责" aria-label="Permalink to &quot;6.1 模块职责&quot;">​</a></h3><p>付款建议模块负责评估计划支出能否付款、是否建议暂缓、是否需要老板介入。它不是简单按金额排序，而是把支出放入现金流曲线中逐笔试算。</p><p>评估结果会持久化到付款建议表。相同支出、相同基准日、相同导入批次、相同规则版本会幂等更新。</p><h3 id="_6-2-资格检查" tabindex="-1">6.2 资格检查 <a class="header-anchor" href="#_6-2-资格检查" aria-label="Permalink to &quot;6.2 资格检查&quot;">​</a></h3><p>当前 MVP 的资格检查主要基于计划支出的审批状态：</p><ul><li>planned、pending：未完成审批，结果为 not_ready；</li><li>approved：进入现金流试算；</li><li>cancelled：不作为有效付款建议。</li></ul><p>目前资料完整性检查还没有独立字段体系，后续可以扩展为“附件是否齐全、合同是否齐全、发票是否齐全、审批链是否完整”等前置检查。</p><h3 id="_6-3-支付顺序" tabindex="-1">6.3 支付顺序 <a class="header-anchor" href="#_6-3-支付顺序" aria-label="Permalink to &quot;6.3 支付顺序&quot;">​</a></h3><p>已审批支出会先排序再逐笔试算。当前排序规则：</p><ol><li>刚性支出优先于可延期支出；</li><li>已经过计划付款日的支出优先；</li><li>计划付款日越早越优先；</li><li>支出编号作为稳定排序兜底。</li></ol><p>这个顺序会影响每笔付款试算后的现金流缺口，因此付款建议不是彼此独立计算，而是一个队列决策。</p><h3 id="_6-4-决策规则" tabindex="-1">6.4 决策规则 <a class="header-anchor" href="#_6-4-决策规则" aria-label="Permalink to &quot;6.4 决策规则&quot;">​</a></h3><p>对每笔已审批支出，系统会在当前现金流曲线上模拟加入该笔付款：</p><ul><li>如果加入后最大现金缺口没有增加，建议 pay；</li><li>如果加入后最大现金缺口增加，且该支出是刚性支出，进入 boss_review；</li><li>如果加入后最大现金缺口增加，且该支出是可延期支出，建议 defer。</li></ul><p>每条建议会保留付款前后最低余额、付款前后最大缺口、缺口增加金额、缺口日期、恢复日期和证据快照。</p><h3 id="_6-5-top-3-展示规则" tabindex="-1">6.5 Top 3 展示规则 <a class="header-anchor" href="#_6-5-top-3-展示规则" aria-label="Permalink to &quot;6.5 Top 3 展示规则&quot;">​</a></h3><p>付款建议 Top 3 的排序优先级为：</p><ol><li>需要老板拍板；</li><li>建议暂缓；</li><li>需要补充依据；</li><li>未就绪；</li><li>可付。</li></ol><p>同一类内部再按缺口增加金额、计划日期和支出编号排序。</p><h2 id="_7-今日老板要拍板模块" tabindex="-1">7. 今日老板要拍板模块 <a class="header-anchor" href="#_7-今日老板要拍板模块" aria-label="Permalink to &quot;7. 今日老板要拍板模块&quot;">​</a></h2><h3 id="_7-1-模块职责" tabindex="-1">7.1 模块职责 <a class="header-anchor" href="#_7-1-模块职责" aria-label="Permalink to &quot;7.1 模块职责&quot;">​</a></h3><p>老板拍板模块不是单独“造”任务，而是从已经计算出的高风险经营事件中抽取需要老板介入的事项，并沉淀成可决策、可留痕、可关闭的事件。</p><p>当前 MVP 事件来源只有两类：</p><ol><li>回款风险升级事件；</li><li>付款建议升级事件。</li></ol><p>现金流缺口本身目前只作为证据，不作为第三类老板事件来源。</p><h3 id="_7-2-回款风险进入拍板的条件" tabindex="-1">7.2 回款风险进入拍板的条件 <a class="header-anchor" href="#_7-2-回款风险进入拍板的条件" aria-label="Permalink to &quot;7.2 回款风险进入拍板的条件&quot;">​</a></h3><p>当应收款风险等级为红色时，会生成或刷新回款风险拍板事件。</p><p>事件证据包含：应收编号、客户名称、应收金额、已回金额、未回金额、约定到账日、逾期天数和命中的原因码。</p><p>老板可选处理方式当前包括：升级催收、继续跟进、调整预计到账日、重新分配负责人。</p><h3 id="_7-3-付款建议进入拍板的条件" tabindex="-1">7.3 付款建议进入拍板的条件 <a class="header-anchor" href="#_7-3-付款建议进入拍板的条件" aria-label="Permalink to &quot;7.3 付款建议进入拍板的条件&quot;">​</a></h3><p>当付款评估结果为 boss_review 时，会生成或刷新付款拍板事件。</p><p>典型原因是：刚性支出必须考虑支付，但支付后会扩大现金流缺口，规则引擎不能替老板选择是补资金、延期其他支出，还是强行支付。</p><p>老板可选处理方式当前包括：支付并补资金、延期付款、调整其他支出、优先催收回款。</p><h3 id="_7-4-事件生命周期" tabindex="-1">7.4 事件生命周期 <a class="header-anchor" href="#_7-4-事件生命周期" aria-label="Permalink to &quot;7.4 事件生命周期&quot;">​</a></h3><p>同一个业务事项使用稳定 business key 识别。系统会优先刷新 pending 事件，而不是重复创建多条事件。</p><p>事件状态包括：</p><ul><li>pending：等待老板处理；</li><li>decided：老板已经选择处理方式；</li><li>closed：风险源已经消失，系统自动关闭。</li></ul><p>提交老板决策时需要带上事件版本号，避免页面打开后数据已刷新而仍提交旧决策。若选项需要补充字段，后端会做必填校验。</p><h2 id="_8-ai-解释模块" tabindex="-1">8. AI 解释模块 <a class="header-anchor" href="#_8-ai-解释模块" aria-label="Permalink to &quot;8. AI 解释模块&quot;">​</a></h2><h3 id="_8-1-模块职责" tabindex="-1">8.1 模块职责 <a class="header-anchor" href="#_8-1-模块职责" aria-label="Permalink to &quot;8.1 模块职责&quot;">​</a></h3><p>AI 模块只服务于“老板点击查看 AI 依据 / AI 解释原因”的交互。它读取已经沉淀的决策事件，把事件标题、类型、风险等级、金额、日期、负责人、原因码、证据快照和可选处理方式传给模型，由模型生成老板可读说明。</p><h3 id="_8-2-接入方式" tabindex="-1">8.2 接入方式 <a class="header-anchor" href="#_8-2-接入方式" aria-label="Permalink to &quot;8.2 接入方式&quot;">​</a></h3><p>当前使用 LangChain 的 OpenAI-compatible Chat 模型封装，默认模型为 qwen-plus，默认兼容接口地址为阿里云 DashScope compatible-mode 地址。</p><p>相关开关包括：是否启用 AI、模型名称、DashScope API Key、Base URL、超时时间和最大重试次数。</p><p>如果未启用 AI 或没有配置 Key，接口不会失败，而是返回确定性降级解释。</p><h3 id="_8-3-输出方式" tabindex="-1">8.3 输出方式 <a class="header-anchor" href="#_8-3-输出方式" aria-label="Permalink to &quot;8.3 输出方式&quot;">​</a></h3><p>AI 解释接口使用 SSE 流式输出。前端可以边接收边展示。</p><p>事件流包含两类消息：</p><ul><li>delta：增量文本；</li><li>done：结束标记，并说明是否为降级输出。</li></ul><h3 id="_8-4-ai-边界" tabindex="-1">8.4 AI 边界 <a class="header-anchor" href="#_8-4-ai-边界" aria-label="Permalink to &quot;8.4 AI 边界&quot;">​</a></h3><p>Prompt 明确要求模型只能解释传入的结构化事实，不重新计算金额，不编造缺失数据，不代替老板做最终决策，并用中文输出适合老板阅读的解释。</p><h2 id="_9-首页概览与任务模块" tabindex="-1">9. 首页概览与任务模块 <a class="header-anchor" href="#_9-首页概览与任务模块" aria-label="Permalink to &quot;9. 首页概览与任务模块&quot;">​</a></h2><h3 id="_9-1-首页概览" tabindex="-1">9.1 首页概览 <a class="header-anchor" href="#_9-1-首页概览" aria-label="Permalink to &quot;9.1 首页概览&quot;">​</a></h3><p>首页概览接口会按当前月返回可用现金、预计回款、实际回款、计划支出、本月现金缺口、逾期未回金额、今日待处理任务数量和四张概览卡片。</p><p>该模块目前更偏“经营概览”，不是具体某个原型卡片的唯一数据源。驾驶舱首页中更细的模块建议优先使用现金流预测、回款风险 Top 3、付款建议 Top 3 和老板拍板事件接口。</p><h3 id="_9-2-任务模块" tabindex="-1">9.2 任务模块 <a class="header-anchor" href="#_9-2-任务模块" aria-label="Permalink to &quot;9.2 任务模块&quot;">​</a></h3><p>发布批次后，系统会根据逾期回款生成催收任务。红色风险任务会标记需要老板介入。</p><p>任务可以查询和更新状态，状态迁移受后端限制。完成任务不等于实际回款到账，实际到账仍必须来自回款数据。</p><h2 id="_10-api-对接优先级" tabindex="-1">10. API 对接优先级 <a class="header-anchor" href="#_10-api-对接优先级" aria-label="Permalink to &quot;10. API 对接优先级&quot;">​</a></h2><p>前端大屏建议优先对接以下接口：</p>',123),a("table",{tabindex:"0"},[a("thead",null,[a("tr",null,[a("th",null,"页面模块"),a("th",null,"接口"),a("th",null,"说明")])]),a("tbody",null,[a("tr",null,[a("td",null,"30 / 60 / 90 天现金流"),a("td",null,"GET /api/v1/cashflow-forecasts"),a("td",null,"返回窗口指标和 90 天逐日曲线")]),a("tr",null,[a("td",null,"回款风险 Top 3"),a("td",null,"GET /api/v1/receivable-risks/top3"),a("td",null,"返回红黄风险前三笔")]),a("tr",null,[a("td",null,"付款建议 Top 3"),a("td",null,"GET /api/v1/payment-recommendations/top3"),a("td",null,"运行并返回付款建议前三笔")]),a("tr",null,[a("td",null,"今日老板要拍板"),a("td",null,"GET /api/v1/decision-events"),a("td",null,"返回待处理拍板事件")]),a("tr",null,[a("td",null,"事件详情"),a("td",{eventId:""},"GET /api/v1/decision-events/"),a("td",null,"查看单个事件证据")]),a("tr",null,[a("td",null,"AI 解释依据"),a("td",null,"GET /api/v1/decision-events/{eventId}/ai-explanation:stream"),a("td",null,"SSE 流式输出解释")]),a("tr",null,[a("td",null,"提交老板决策"),a("td",null,"POST /api/v1/decision-events/{eventId}:decide"),a("td",null,"写入老板选择和备注")])])],-1),a("p",null,"后台审核和排查建议对接：",-1),a("table",{tabindex:"0"},[a("thead",null,[a("tr",null,[a("th",null,"后台能力"),a("th",null,"接口")])]),a("tbody",null,[a("tr",null,[a("td",null,"上传 Excel"),a("td",null,"POST /api/v1/imports")]),a("tr",null,[a("td",null,"导入批次列表"),a("td",null,"GET /api/v1/imports")]),a("tr",null,[a("td",null,"批次详情"),a("td",{batchId:""},"GET /api/v1/imports/")]),a("tr",null,[a("td",null,"原始行查看"),a("td",null,"GET /api/v1/imports/{batchId}/rows")]),a("tr",null,[a("td",null,"校验错误查看"),a("td",null,"GET /api/v1/imports/{batchId}/validation-errors")]),a("tr",null,[a("td",null,"发布批次"),a("td",null,"POST /api/v1/imports/{batchId}:publish")]),a("tr",null,[a("td",null,"标准数据预览"),a("td",null,"账户余额、客户、应收款、实际回款、计划支出预览接口")])])],-1),e('<h2 id="_11-已实现验证" tabindex="-1">11. 已实现验证 <a class="header-anchor" href="#_11-已实现验证" aria-label="Permalink to &quot;11. 已实现验证&quot;">​</a></h2><p>当前后端已有覆盖以下链路的测试：</p><ul><li>Excel 样本上传、解析、发布；</li><li>无已发布批次时的统一错误格式；</li><li>首页概览核心指标；</li><li>回款风险等级；</li><li>90 天现金流曲线和 30 / 60 / 90 窗口；</li><li>回款风险 Top 3；</li><li>付款建议 Top 3；</li><li>老板拍板事件生成；</li><li>AI 解释接口在未配置模型时的降级 SSE 输出；</li><li>老板决策提交和事件状态流转；</li><li>现金流基础计算函数。</li></ul><h2 id="_12-当前明确边界与待确认事项" tabindex="-1">12. 当前明确边界与待确认事项 <a class="header-anchor" href="#_12-当前明确边界与待确认事项" aria-label="Permalink to &quot;12. 当前明确边界与待确认事项&quot;">​</a></h2><p>以下事项目前不阻塞 MVP 前端对接，但会影响后续产品口径：</p><ol><li>安全线当前暂定为 0，后续可能需要 CFO 确认为固定金额、月支出倍数或账户维度安全线。</li><li>计划支出缺少真实付款表，支出状态如果不更新，可能重复进入预测。</li><li>付款资料完整性当前没有字段化，只按审批状态做前置判断。</li><li>临期回款当前定义为到期当天到未来 2 天，需要产品和 CFO 确认。</li><li>回款红色风险阈值当前为逾期 30 天或逾期且未回金额大于等于 100 万，需要结合企业实际确认。</li><li>老板拍板事件目前只来源于回款风险和付款建议；现金缺口是否单独生成拍板事件暂不做。</li><li>AI 解释当前按需生成，不持久化解释文本；如需审计留痕，后续可以增加解释记录表。</li><li>当前登录和权限不是重点，正式使用前仍需补认证、RBAC 和审计字段。</li></ol><h2 id="_13-后续建议" tabindex="-1">13. 后续建议 <a class="header-anchor" href="#_13-后续建议" aria-label="Permalink to &quot;13. 后续建议&quot;">​</a></h2><p>短期建议先做三件事：</p><ol><li>前端大屏优先接入已实现的四个驾驶舱模块接口，先形成一版真实数据闭环。</li><li>用财务下周提供的真实收入数据跑一轮导入和发布，重点核对现金流曲线、逾期回款和付款建议。</li><li>把 CFO 确认后的安全线、临期定义、红色阈值、付款优先级规则固化为下一个规则版本。</li></ol><p>中期再考虑补齐：更灵活的数据清洗管道、真实付款事实表、AI 解释留痕、权限和审计、指标依据下钻。</p>',10)])])}const b=i(o,[["render",n]]);export{_ as __pageData,b as default};
